import React from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ jiraData, onSelectUserStory, onClose }) {
  return (
    <div className="sidebar">
      <div className="sidebar-header">
        <h3>Imported Jira User Stories</h3>
        {/* Close button (X) */}
        <button className="close-btn" onClick={onClose}>X</button>
      </div>
      {jiraData.length === 0 ? (
        <p>No Data Imported</p>
      ) : (
        <div className="jira-data">
          {jiraData.map((data) => (
            <div
              key={data.id}
              className="jira-data-block"
              onClick={() => onSelectUserStory(data.story)} // Pass the selected story to the chat box
            >
              <h4>User Story {data.id}</h4>
              <p>{data.story}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default ImportDataSidebar;
